// File-selection logic (B1): fs.copyFileSync only, no heavy objects
// held in node memory. Slices the master set into one derived copy
// per tier -- each holds exactly that tier's components, nothing more.
// The master set itself never leaves Working (A9 non-negotiables).

const fs = require('fs');
const path = require('path');

const prefix = $json.project_prefix;
const tierMap = JSON.parse(fs.readFileSync(path.join('Working', prefix, 'tier_map.json'), 'utf8'));
const masterDir = path.join('Working', prefix, 'master_set');

const tierFiles = {
  lowest: ['compliance_checklist.md'],
  mid: ['sow_budget.md'],
  full: ['compliance_checklist.md', 'end_to_end_drafting.md', 'sow_budget.md']
};

for (const tier of Object.keys(tierFiles)) {
  const destDir = path.join('Working', prefix, 'derived', tier);
  fs.mkdirSync(destDir, { recursive: true });
  for (const fname of tierFiles[tier]) {
    const src = path.join(masterDir, fname);
    const dest = path.join(destDir, fname);
    if (fs.existsSync(src)) {
      fs.copyFileSync(src, dest); // fs.copyFileSync only -- no buffer held in memory
    }
  }
}

return [{ json: { project_prefix: prefix, derived_complete: true } }];
